```javascript
function makeItFly(creature) {
  // The function doesn't care if 'creature' is a Bird, a Plane, or a Robot.
  // It only cares that 'creature' has a 'fly' method.
  creature.fly(); 
}

const bird = {
  name: "Tweety",
  fly: () => console.log("Flap flap!")
};

const plane = {
  name: "Boeing 747",
  fly: () => console.log("Zoom!")
};

```typescript
interface Flyable {
  fly(): void;
}

function makeItFly(creature: Flyable) {
  creature.fly();
}

const bird: Flyable = {
  name: "Tweety",
  fly: () => console.log("Flap flap!")
};

// This will cause a COMPILE ERROR:
// "Argument of type '{ name: string; }' is not assignable to parameter of type 'Flyable'."
// because the object lacks the 'fly' method.
const brokenObject = { name: "Rock" }; 
makeItFly(brokenObject); 
```

